{"command": "cd /data/zrwang/auto-opt/utils/llvm-60167 && python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Analysis/InstructionSimplify.cpp 4611 4619 << 'EOF'
    // select (select X, Y, false), true, X --> X
    // select (select X, Y, false), true, Y --> Y
    // (select X, Y, false) is equivalent to (X && Y)
    // So: (X && Y) ? true : X --> X  and  (X && Y) ? true : Y --> Y
    // Also handle commuted inner select: select X, false, Y <=> select X, Y, false
    Value *InnerCond, *InnerTV, *InnerFV;
    if (match(Cond, m_Select(m_Value(InnerCond), m_Value(InnerTV), m_Value(InnerFV))) &&
        match(TrueVal, m_One())) {
      // Check if inner select is equivalent to (InnerCond && InnerTV): select ?, ?, false
      if (match(InnerFV, m_ZeroInt())) {
        if (FalseVal == InnerCond || FalseVal == InnerTV)
          return FalseVal;
      }
      // Check if inner select is equivalent to (InnerCond && InnerFV): select ?, false, ?
      if (match(InnerTV, m_ZeroInt())) {
        if (FalseVal == InnerCond || FalseVal == InnerFV)
          return FalseVal;
      }
    }
EOF"}

